// Map BoldTrail Zapier fields to Norr AI standard payload shape.
// IMPORTANT: Verify field names against actual Zapier trigger output before going live.
// Open the Zap, run a test, and inspect the 'Available fields' panel to confirm.
const b = $input.first().json.body || $input.first().json;

const firstName = b.first_name || b.contact_first_name || '';
const lastName = b.last_name || b.contact_last_name || '';
const fullName = b.full_name || b.contact_name || `${firstName} ${lastName}`.trim();

const minPrice = b.min_price || b.price_min || '';
const maxPrice = b.max_price || b.price_max || '';
const priceRange = b.price_range || (minPrice ? `$${minPrice}–$${maxPrice}` : '');

return [{
  json: {
    client_token: 'CLIENT_TOKEN_PLACEHOLDER',
    lead_name: fullName,
    email: b.email || b.contact_email || '',
    phone: b.phone || b.contact_phone || b.phone_number || '',
    source: 'boldtrail',
    property_address: b.address || b.property_address || b.street_address || '',
    price_range: priceRange,
    beds: b.min_beds || b.bedrooms || b.beds || null,
    lead_message: b.notes || b.message || b.lead_notes || 'BoldTrail lead'
  }
}];
